10	/**
11	 * Profile (`/profile`, ADR 0022 ProfileScreen). The account screen: an identity
12	 * card + workspace facts, both rendered only from `/me` (KPI honesty — no
13	 * fabricated fields), plus an Alert-channels card.
14	 *
15	 * Alerting is configured **per suite** (the W6 `ResultPublisher` + per-suite
16	 * notification config), not per user, so this card states that honestly and
17	 * links to the suites rather than showing per-user toggles no backend backs.
18	 */
19	export function Profile() {
20	  const me = useMe();
21	
22	  if (me.status === 'loading') {
23	    return <Spin size="large" style={{ marginTop: 80 }} />;
24	  }
25	  if (me.status === 'error') {
26	    return (
27	      <Alert type="error" showIcon title="Failed to load your profile" description={me.error} />
28	    );
29	  }
30	
31	  const { display_name, email, last_seen_at, is_workspace_admin } = me.data;
32	  const name = display_name ?? email;
33	  const initial = (name || '?').trim().charAt(0).toUpperCase();
34	
35	  return (
36	    <Page width="form" gap={16}>
37	      <Typography.Title level={3} style={{ margin: 0 }}>
38	        Profile
39	      </Typography.Title>
40	
41	      <Card>
42	        <Flex gap={16} align="center">
43	          <Avatar size={56} style={{ backgroundColor: BRAND.primary }}>
44	            {initial}
45	          </Avatar>
46	          <Flex vertical gap={2}>
47	            <Typography.Text strong style={{ fontSize: 18 }}>
48	              {name}
49	            </Typography.Text>
50	            <Typography.Text type="secondary">{email}</Typography.Text>
51	            <span>
52	              <Tag color={is_workspace_admin ? 'gold' : 'default'}>
53	                {is_workspace_admin ? 'Workspace admin' : 'Member'}
54	              </Tag>
55	            </span>
56	          </Flex>
57	        </Flex>
58	      </Card>
59	
60	      <Card title="Workspace" size="small">
61	        <Descriptions column={1} size="small">
62	          <Descriptions.Item label="Authentication">Azure AD (MSAL)</Descriptions.Item>
63	          <Descriptions.Item label="Role">
64	            {is_workspace_admin ? 'Workspace admin' : 'Member'}
65	          </Descriptions.Item>
66	          <Descriptions.Item label="Last seen">{last_seen_at ?? '—'}</Descriptions.Item>
67	        </Descriptions>
68	      </Card>
69	
70	      <Card
71	        title={
72	          <Flex gap={8} align="center">
73	            <TeamOutlined /> Alert channels
74	          </Flex>
75	        }
76	        size="small"
77	      >
78	        <Alert
79	          type="info"
80	          showIcon
81	          icon={<UserOutlined />}
82	          title="DQ alerts are configured per suite"
83	          description={
84	            <span>
85	              Microsoft Teams alerts (webhook + fail / warn / always threshold) are set on each
86	              suite, so the right team is notified for the data they own. Open a suite from{' '}
87	              <Link to="/suites">Suites</Link> to configure its notifications.
88	            </span>
89	          }
90	        />
91	      </Card>
92	
93	      <ApiKeysPanel />
94	    </Page>
95	  );
96	}
